import{c as a,Q as i,j as n,m as p}from"./chunks/framework.iD28w_5a.js";const o=JSON.parse('{"title":"003-boot-long-mode-3 · Long Mode","description":"","frontmatter":{"title":"003-boot-long-mode-3 · Long Mode"},"headers":[],"relativePath":"tutorial/003-boot-long-mode-3.md","filePath":"tutorial/003-boot-long-mode-3.md","lastUpdated":1779686691000}'),e={name:"tutorial/003-boot-long-mode-3.md"};function l(t,s,h,r,k,F){return i(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="higher-half-kernel-为什么-0xffffffff80000000-能找到物理地址-0x0" tabindex="-1">Higher-Half Kernel：为什么 0xFFFFFFFF80000000 能找到物理地址 0x0 <a class="header-anchor" href="#higher-half-kernel-为什么-0xffffffff80000000-能找到物理地址-0x0" aria-label="Permalink to &quot;Higher-Half Kernel：为什么 0xFFFFFFFF80000000 能找到物理地址 0x0&quot;">​</a></h1><blockquote><p>标签：x86_64, 高半内核, Higher-Half, 双映射, PML4[511], PDPT[510] 前置：<a href="./003-boot-long-mode-2">003-2 模式切换</a></p></blockquote><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>前两篇我们把四级页表搭好了、把 CPU 从保护模式带到了 Long Mode，输出 <code>L</code> 宣告胜利。</p><p>但如果你仔细看了 <code>setup_page_tables</code> 的完整代码，会发现恒等映射的循环之后、<code>ret</code> 之前还有一段代码——</p><p>它设置了 PML4[511] 和 PDPT[510]，</p><p>把虚拟地址 0xFFFFFFFF80000000 映射到物理地址 0x00000000。</p><p>这一段代码只有 8 条指令，但背后的地址计算和设计决策值得单独用一篇来展开。</p><p>因为如果不理解 &quot;为什么 PDPT 索引是 510 而不是 511&quot; 这个问题，</p><p>将来你自己设计页表映射时一定会踩坑。</p><h2 id="higher-half-是什么-为什么需要它" tabindex="-1">Higher-Half 是什么，为什么需要它 <a class="header-anchor" href="#higher-half-是什么-为什么需要它" aria-label="Permalink to &quot;Higher-Half 是什么，为什么需要它&quot;">​</a></h2><p>操作系统的内核通常运行在虚拟地址空间的高地址区域，把低地址区域留给用户进程。</p><p>Linux、Windows、macOS 都是这么做的。</p><p>以 Linux 为例，在典型的 48 位地址空间配置下，</p><p>用户空间占低地址的 0x0000000000000000 到 0x00007FFFFFFFFFFF（128TB），</p><p>内核空间占高地址的 0xFFFF800000000000 到 0xFFFFFFFFFFFFFFFF</p><p>（也是 128TB，但实际使用范围取决于配置）。</p><p>这种设计的核心好处是隔离。</p><p>用户程序的虚拟地址空间从 0 开始，内核的虚拟地址空间在高处，两者互不干扰。</p><p>当内核需要访问用户空间时，可以通过 <code>copy_to_user</code> / <code>copy_from_user</code> 等机制安全地跨越边界。</p><p>而且，高半内核的地址（比如 0xFFFFFFFF80000000）对于用户程序来说是&quot;不可达&quot;的——</p><p>canonical address 检查会阻止用户态代码访问高地址区域。</p><p>Cinux 的内核入口地址被设定为 0xFFFFFFFF80020000。</p><p>内核被加载到物理地址 0x20000（在第一个 2MB 大页范围内），</p><p>但 C++ 代码是按高半地址编译链接的——</p><p>函数指针、全局变量的地址都是 0xFFFFFFFF80XXXXXX 的形式。</p><p>如果 Bootloader 不建立 Higher-Half 映射，</p><p>内核代码跳转到 0xFFFFFFFF80020000 时会发现那个虚拟地址没有对应的物理页，直接 page fault。</p><p>所以 Higher-Half 映射不是一个可选项，而是让内核&quot;能跑起来&quot;的必要条件。</p><h2 id="逆向工程-从虚拟地址到页表索引" tabindex="-1">逆向工程：从虚拟地址到页表索引 <a class="header-anchor" href="#逆向工程-从虚拟地址到页表索引" aria-label="Permalink to &quot;逆向工程：从虚拟地址到页表索引&quot;">​</a></h2><p>要理解 PML4[511] 和 PDPT[510] 是怎么来的，</p><p>我们需要把虚拟地址 0xFFFFFFFF80000000 拆开来看。</p><p>这个过程就像逆向工程——</p><p>从最终结果（一个 64 位地址）反推它在四级页表中的查找路径。</p><p>x86-64 使用 48 位有效虚拟地址。</p><p>虚拟地址的高 16 位是符号扩展（canonical address 要求），bit 47 到 bit 0 是实际参与页表查找的地址。</p><p>这 48 位被拆分为四段 9 位索引和一段 12 位页内偏移：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>虚拟地址 0xFFFFFFFF80000000:</span></span>
<span class="line"><span>高位: 0xFFFF = 符号扩展 (bit 63:48)</span></span>
<span class="line"><span>PML4 索引 (bit 47:39) = 0x1FF = 511</span></span>
<span class="line"><span>PDPT 索引 (bit 38:30) = 0x1FE = 510</span></span>
<span class="line"><span>PD 索引   (bit 29:21) = 0x000 = 0</span></span>
<span class="line"><span>PT 索引   (bit 20:12) = 0x000 = 0 (不使用，因为是 2MB 大页)</span></span>
<span class="line"><span>页内偏移  (bit 11:0)  = 0x000 = 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>关键在于 bit 30。</p><p>0x80000000 在二进制中是 <code>1000 0000 0000 0000 0000 0000 0000 0000</code>，bit 30 的值是 0。</p><p>PDPT 索引取的是 bit 38:30，所以 bit 38 到 bit 31 全是 1（因为符号扩展）、bit 30 是 0，</p><p>结果是 <code>0b1_1111_1110 = 0x1FE = 510</code>。</p><p>这个 &quot;510 而不是 511&quot; 是一个很容易犯的 off-by-one 错误。</p><p>直觉上你可能觉得 PML4 用了 511（最后一条），PDPT 也应该用 511（最后一条），</p><p>但虚拟地址的位分布不是均匀的——</p><p>0x80000000 恰好在 bit 30 上是 0，导致 PDPT 索引比 PML4 索引少了 1。</p><p>如果你错误地把 PDPT[511] 设成指向 PD，</p><p>对应的虚拟地址是 0xFFFFFFFFC0000000 而不是 0xFFFFFFFF80000000——差了整整 1GB，</p><p>而且这种错误在调试时非常难发现，因为 CPU 不会报错，只是映射到了错误的地址。</p><h2 id="代码详解-八条指令完成-higher-half-映射" tabindex="-1">代码详解：八条指令完成 Higher-Half 映射 <a class="header-anchor" href="#代码详解-八条指令完成-higher-half-映射" aria-label="Permalink to &quot;代码详解：八条指令完成 Higher-Half 映射&quot;">​</a></h2><p>整个 Higher-Half 映射只需要 8 条指令——</p><p>4 条设置 PML4[511]，4 条设置 PDPT[510]：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    // PML4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] -&gt; PDPT (same as PML4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl $PDPT_PHYS_ADDR, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">       // PDPT physical address = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x2000</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    orl $0x03, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                   // </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> present+writable </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">flags</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PML4_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  // PML4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] low </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bits</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PML4_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) + </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  // PML4[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] high </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bits = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    // PDPT[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] -&gt; PD (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NOT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">! </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x80000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> has bit </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl $PD_PHYS_ADDR, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">         // PD physical address = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x3000</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    orl $0x03, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                   // </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> present+writable </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">flags</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">eax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PDPT_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  // PDPT[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] low </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bits</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    movl </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PDPT_PHYS_ADDR + (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> * </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) + </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  // PDPT[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">510</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] high </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bits = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>PML4[511] 的内存偏移是 0x1000 + (511 * 8) = 0x1000 + 0xFF8 = 0x1FF8——PML4 的最后一个条目。</p><p>PDPT[510] 的偏移是 0x2000 + (510 * 8) = 0x2000 + 0x0FE0 = 0x2FE0——PDPT 的倒数第二个条目。</p><p>这段代码的关键设计是复用。</p><p>PML4[511] 和 PML4[0] 指向同一张 PDPT 表（0x2000），</p><p>PDPT[510] 和 PDPT[0] 指向同一张 PD 表（0x3000），</p><p>PD[0] 是恒等映射阶段设好的 0-2MB 大页条目。</p><p>这样 Higher-Half 映射不需要分配任何额外的页表页面——</p><p>只需要在已有的表中添加两个链接条目。</p><p>另一个值得注意的细节是显式写高 32 位为 0。</p><p>对于恒等映射部分（PML4[0] 和 PDPT[0]），</p><p>代码只写了低 32 位，高 32 位依赖清零操作保证。</p><p>但 Higher-Half 部分显式写了 <code>movl $0, offset+4</code>。</p><p>这是一个有意为之的设计选择——</p><p>它让代码的意图更清晰，不需要读者回头确认&quot;清零操作是否覆盖了这个位置&quot;。</p><p>Intel SDM Vol.3A §4.5 明确要求页表条目中未实现的保留位必须为 0，否则会触发 #GP。</p><p>显式写 0 是对这个要求的直接回应。</p><h2 id="双映射的威力" tabindex="-1">双映射的威力 <a class="header-anchor" href="#双映射的威力" aria-label="Permalink to &quot;双映射的威力&quot;">​</a></h2><p>完成 Higher-Half 映射后，物理内存 0x00000000-0x001FFFFF（前 2MB）可以通过两条不同的虚拟地址路径访问：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>路径 1（恒等映射）：</span></span>
<span class="line"><span>虚拟地址 0x0000000000000000 - 0x00000000001FFFFF</span></span>
<span class="line"><span>PML4[0] → PDPT → PDPT[0] → PD → PD[0] → 物理 0-2MB</span></span>
<span class="line"><span></span></span>
<span class="line"><span>路径 2（Higher-Half 映射）：</span></span>
<span class="line"><span>虚拟地址 0xFFFFFFFF80000000 - 0xFFFFFFFF801FFFFF</span></span>
<span class="line"><span>PML4[511] → PDPT → PDPT[510] → PD → PD[0] → 物理 0-2MB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这两条路径最终都到达 PD[0]（值 0x83，映射物理 0-2MB），</p><p>但走了不同的 PML4 和 PDPT 条目。</p><p>双映射在操作系统启动阶段非常重要——</p><p>CPU 在刚进入 Long Mode 时使用恒等映射地址执行代码（因为 EIP 还是指向低地址），</p><p>后续通过一次远跳转切换到 Higher-Half 地址。</p><p>在切换过程中，两条路径必须同时有效，否则 CPU 会在切换的瞬间找不到下一条指令。</p><p>内核入口地址 0xFFFFFFFF80020000 的翻译过程：</p><p>PML4[511]（=0x2003）找到 PDPT，PDPT[510]（=0x3003）找到 PD，</p><p>PD[0]（=0x83）映射物理 0-2MB，页内偏移 0x20000，最终物理地址 = 0x0000000000020000。</p><p>正好是内核被加载到的物理地址。</p><h2 id="xv6-的做法——对比" tabindex="-1">xv6 的做法——对比 <a class="header-anchor" href="#xv6-的做法——对比" aria-label="Permalink to &quot;xv6 的做法——对比&quot;">​</a></h2><p>MIT 的 xv6（<a href="https://github.com/mit-pdos/xv6-public" target="_blank" rel="noreferrer">GitHub</a>）是一个 32 位操作系统，</p><p>完全没有 Higher-Half 的概念——</p><p>内核和用户程序共享同一个虚拟地址空间，内核就在低地址。</p><p>这种设计简单但不安全——用户程序可以直接读写内核内存。</p><p>xv6 的 64 位移植版本（swetland/xv6）需要处理 Higher-Half 映射，</p><p>做法和 Cinux 类似：</p><p>PML4[256] 做内核映射（对应虚拟地址 0xFFFFFF0000000000），PML4[0] 做用户空间映射。</p><p>Linux 的做法更复杂：</p><p>它用 PML4 的后半部分（index 256-511）映射内核空间，前半部分（index 0-255）留给用户空间。</p><p>内核的线性映射区域从 0xFFFFFFFF80000000 开始</p><p>（或 0xFFFF888000000000 的直接映射区，取决于 KASLR 配置），</p><p>和 Cinux 使用了相同的地址模式。</p><h2 id="验证方法" tabindex="-1">验证方法 <a class="header-anchor" href="#验证方法" aria-label="Permalink to &quot;验证方法&quot;">​</a></h2><p>在 GDB 中可以在 <code>setup_page_tables</code> 返回后检查 Higher-Half 相关的条目：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) x/1gx 0x1000 + 511*8       # PML4[511] = 0x2003</span></span>
<span class="line"><span>(gdb) x/1gx 0x2000 + 510*8       # PDPT[510] = 0x3003</span></span>
<span class="line"><span>(gdb) x/1gx 0x3000                # PD[0] = 0x83 (shared with identity mapping)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果 PML4[511] 和 PML4[0] 的值相同（都是 0x2003），</p><p>PDPT[510] 和 PDPT[0] 的值相同（都是 0x3003），说明 Higher-Half 映射正确建立。</p><p>你也可以在 64 位模式下用 <code>x/1gx 0xFFFFFFFF80000000</code> 验证是否能正确读取到物理地址 0x0 处的数据。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>Higher-Half 映射看起来只是多设了两个页表条目，</p><p>但背后的虚拟地址拆分、索引计算、双映射设计都是操作系统页表管理的基础知识。</p><p>理解了 &quot;为什么 PDPT 索引是 510 而不是 511&quot;，</p><p>你就掌握了手动计算任意虚拟地址对应的四级页表索引的能力——</p><p>这在将来调试页表相关 bug 时是最重要的技能。</p><p>Tag 003 到这里就全部完成了。</p><p>CPU 运行在 64 位 Long Mode 下，恒等映射和 Higher-Half 映射都正常工作，</p><p>64 位寄存器、四级页表、64 位栈全部就绪。</p><p>下一篇（tag 004）我们将继续往上走——</p><p>在 Long Mode 下填充 BootInfo 结构、跳转到 C++ 内核入口。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM Vol.3A §4.5 — 4-Level Paging：PML4/PDPT/PD/PT 层级结构</li><li>Intel SDM Vol.3A §4.5.1 — Page Size Extensions：2MB 大页的基地址计算</li><li>Intel SDM Vol.3A §10.8.5 — Initializing IA-32e Mode：完整的 Long Mode 初始化步骤</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Setting_Up_Long_Mode" target="_blank" rel="noreferrer">Setting Up Long Mode</a></li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Higher_Half_Kernel" target="_blank" rel="noreferrer">Higher Half Kernel</a></li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Paging" target="_blank" rel="noreferrer">Paging</a></li><li>Linux kernel: <a href="https://0xax.gitbooks.io/linux-insides/content/Booting/linux-bootstrap-4.html" target="_blank" rel="noreferrer">head_64.S</a></li><li>xv6: <a href="https://github.com/mit-pdos/xv6-public" target="_blank" rel="noreferrer">GitHub</a> — 32 位版本不做 Higher-Half</li></ul>`,114)])])}const g=a(e,[["render",l]]);export{o as __pageData,g as default};
